    // Use span() to get a zero-copy view of packet_id (first 4 bytes)
    auto id_span = stream.span(sizeof(uint32_t));
    std::memcpy(&info.packet_id, id_span.data(), sizeof(uint32_t));

    // Read username using prefixed adaptor to get string_view
    info.username = stream.read_prefixed_view();

    // Skip the scores vector without reading elements
    uint32_t score_count;
    stream >> score_count;
    stream.skip(score_count * sizeof(uint32_t));

    return info;
}

