#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
    uint32_t footer;
};

MessageHeader read_header_and_skip_body(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the span
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream from the adaptor
    hexi::binary_stream stream(adaptor);

    // Read the header fields
    MessageHeader header;
    stream >> header.message_type;  // Read message_type (uint16_t)
    stream >> header.body_length;    // Read body_length (uint32_t)

    // Skip the body data
    stream.skip(header.body_length);

    // Read the footer
    stream >> header.footer;         // Read footer (uint32_t)

    return header;
}
```

## Explanation:

1. **Create buffer adaptor**: `hexi::buffer_adaptor` wraps the `std::span<const uint8_t>` to make it compatible with Hexi's binary stream
2. **Create binary stream**: `hexi::binary_stream` provides methods for reading binary data
3. **Read values**: Use the extraction operator `>>` to read typed values in sequence
4. **Skip body**: Use `skip()` method to advance the stream position by `body_length` bytes without reading the data
5. **Read footer**: Continue reading after the skipped body data to get the footer value
6. **Return result**: Return the populated `MessageHeader` struct

