    // Create a buffer adaptor from the source buffer
    hexi::buffer_adaptor adaptor(source_buffer);

    // Create a binary stream for reading
    hexi::binary_stream stream(adaptor);

    // Create destination vector and read bytes one by one
    std::vector<uint8_t> result(bytes_to_read);
    for (size_t i = 0; i < bytes_to_read; ++i) {
        stream >> result[i];
    }

    return result;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Create a buffer adaptor from the destination buffer
    hexi::buffer_adaptor adaptor(dest_buffer);

    // Create a binary stream for writing
    hexi::binary_stream stream(adaptor);

    // Write each byte from source to destination using stream operator
    for (const auto& byte : source_data) {
        stream << byte;
    }
}

