```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Calculate required space
    // header: 4 bytes + container size prefix: 4 bytes + items data: items.size() * 4 bytes
    size_t required_space = sizeof(uint32_t) + sizeof(uint32_t) + items.size() * sizeof(uint32_t);

    // Get current buffer size
    size_t current_size = buffer.size();

    // Check available space and reserve if needed
    if (buffer.capacity() < current_size + required_space) {
        try {
            buffer.reserve(current_size + required_space);
        } catch (const std::bad_alloc&) {
            return false;  // Insufficient space
        }
    }

    // Create buffer adaptor
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream with no_throw to handle errors gracefully
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Write header
    stream << header;

    // Write container data
    stream.write_container(items);

    // Return true if write was successful, false otherwise
    return static_cast<bool>(stream);
}
