#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create block_allocator for uint64_t with element_count blocks
    hexi::block_allocator<std::uint64_t, element_count> allocator;

    std::cout << "=== Demonstrating block_allocator free list management ===" << std::endl;
    std::cout << "Initial state - all blocks in free list" << std::endl;
    std::cout << "Total blocks available: " << element_count << std::endl << std::endl;

    // Vector to store allocated pointers
    std::vector<std::uint64_t*> allocated_blocks;

    // Demonstrate pop() behavior through allocate()
    // Each allocate() internally calls pop() to remove a block from the free list
    std::cout << "Allocating blocks (internally calling pop()):" << std::endl;
    for (size_t i = 0; i < element_count; ++i) {
