    EXPECT_EQ(4, header.size());
    EXPECT_EQ(0x01, header[0]);
    EXPECT_EQ(0x02, header[1]);
    EXPECT_EQ(0x03, header[2]);
    EXPECT_EQ(0x04, header[3]);

    std::filesystem::remove(test_file);
}

TEST(FileBuffer, PreviewHeaderMultipleTimes) {
    std::filesystem::path test_file = "test_header2.bin";
    std::vector<uint8_t> test_data = {10, 20, 30, 40, 50};
