#include <gtest/gtest.h>
#include <hexi/exception.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

// Include the implementation
#include "implementation.hpp"

TEST(BufferUnderrun, CatchException) {
    auto info = catch_buffer_underrun();

    EXPECT_TRUE(info.occurred);
    EXPECT_GT(info.read_size, 0);
    EXPECT_GE(info.buff_size, 0);
}

TEST(BufferUnderrun, SafeReadSuccess) {
    std::vector<std::byte> storage;
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint32_t value = 12345;
    adaptor.write(&value, sizeof(value));

    uint32_t read_value = 0;
    auto info = safe_read_with_underrun_check(adaptor, &read_value, sizeof(read_value));

    EXPECT_FALSE(info.occurred);
    EXPECT_EQ(value, read_value);
}

TEST(BufferUnderrun, SafeReadFailure) {
    std::vector<std::byte> storage(10);
    hexi::pmc::buffer_adaptor adaptor(storage);

    std::vector<std::byte> dest(100);
    auto info = safe_read_with_underrun_check(adaptor, dest.data(), 100);

    EXPECT_TRUE(info.occurred);
