#include <hexi/exception.h>
#include <hexi/pmc/binary_stream.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct ReadLimitInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t read_limit;
    bool occurred;
};

ReadLimitInfo catch_stream_read_limit() {
    try {
        throw; // re-throw the current exception
    } catch (const hexi::exception::stream_read_limit& e) {
        return ReadLimitInfo{
            e.read_size(),
            e.total_read(),
            e.read_limit(),
            true
        };
    } catch (...) {
        // Not a stream_read_limit exception or no exception
        return ReadLimitInfo{0, 0, 0, false};
    }
}

ReadLimitInfo safe_read_with_limit_check(hexi::pmc::binary_stream& stream, void* destination, std::size_t length) {
    try {
        stream.read(destination, length);
        // Read succeeded without hitting the limit
        return ReadLimitInfo{0, 0, 0, false};
    } catch (const hexi::exception::stream_read_limit& e) {
        // Extract exception information
        return ReadLimitInfo{
            e.read_size(),
            e.total_read(),
            e.read_limit(),
            true
        };
    }
}
```

**Explanation:**

1. **`catch_stream_read_limit()`**: This function is designed to be called from within a catch block. It uses `throw;` to re-throw the current exception, then catches `hexi::exception::stream_read_limit` specifically. It extracts the three key pieces of information (`read_size`, `total_read`, `read_limit`) using the exception's getter methods and sets `occurred` to `true`. If it's not a `stream_read_limit` exception, it returns default values with `occurred = false`.

2. **`safe_read_with_limit_check()`**: This function wraps a stream read operation in a try-catch block. It attempts to read `length` bytes from the stream into the `destination` buffer. If the read succeeds, it returns a `ReadLimitInfo` with `occurred = false`. If a `stream_read_limit` exception is thrown (because the read would exceed the imposed limit), it catches the exception and returns the detailed information about what limit was exceeded.

