    original.message_id = 0x11111111;
    original.data_values = {};
    original.checksum = 0x22222222;

    auto buffer = serialize_protocol_packet(original);

    ProtocolPacket deserialized = deserialize_protocol_packet(buffer);

    EXPECT_EQ(original.message_id, deserialized.message_id);
    EXPECT_TRUE(deserialized.data_values.empty());
